@@ -2965,6 +2965,7 @@ <h5 class="text-xs font-semibold text-gray-600 dark:text-gray-400 uppercase trac
            x-transition:leave="transition ease-in duration-200"
            x-transition:leave-start="md:translate-x-0 translate-y-0"
            x-transition:leave-end="md:translate-x-full translate-y-full"
+           @keydown.escape.window="if (graphDetailNode && !selectedIssue) { graphDetailNode = null; if(forceGraphModule?.clearSelection) forceGraphModule.clearSelection(); setTimeout(() => resizeForceGraph(), 250); }"
            @touchstart.passive="touchStartY = $event.touches[0].clientY; touchStartX = $event.touches[0].clientX; touchCurrentY = touchStartY; touchCurrentX = touchStartX; swiping = true"
            @touchmove.passive="if(swiping) { touchCurrentY = $event.touches[0].clientY; touchCurrentX = $event.touches[0].clientX; if(isMobile && touchCurrentY > touchStartY) { $el.style.transform = 'translateY(' + Math.max(0, touchCurrentY - touchStartY) + 'px)'; } else if(!isMobile && touchCurrentX > touchStartX) { $el.style.transform = 'translateX(' + Math.max(0, touchCurrentX - touchStartX) + 'px)'; } }"
            @touchend="if(swiping) { const swipeY = touchCurrentY - touchStartY; const swipeX = touchCurrentX - touchStartX; if((isMobile && swipeY > 100) || (!isMobile && swipeX > 100)) { graphDetailNode = null; if(forceGraphModule?.clearSelection) forceGraphModule.clearSelection(); setTimeout(() => resizeForceGraph(), 250); } $el.style.transform = ''; swiping = false; }"

@@ -269,9 +269,13 @@ func (c *metricsCache) ensureFresh() error {
 		return nil
 	}

-	// Use singleflight to prevent cache stampede: callers that observe the same
-	// source hash coalesce into a single refresh attempt for that snapshot.
-	_, err, _ = c.sf.Do(metricsCacheRefreshFlightKey+":"+hash, func() (interface{}, error) {
+	// Use singleflight to prevent cache stampede. Key is constant (not
+	// hash-suffixed) so concurrent refreshes coalesce even when callers
+	// observed different source hashes mid-drift — otherwise two workers that
+	// each compute a slightly different hash trigger two parallel Refresh()
+	// calls, defeating the stampede guard. After Refresh() runs once, every
+	// coalesced caller observes the latest snapshot in the cache.
+	_, err, _ = c.sf.Do(metricsCacheRefreshFlightKey, func() (interface{}, error) {
 		if c.isFreshForHash(hash) {
 			return nil, nil
 		}
